/** Transferable-credit totals and rules noted in the source sheet. */
export const EQUIVALENCY_RULES: string[] = [
  "Banking Transferable Courses = 70 Credits",
  "Insurance Course Transferable Courses = 62 Credits",
  "Management Diploma Course Transferable Courses = 70 Credits",
  "Material Diploma Total number of transferrable credits is 63",
  "Accounting Diploma = Transferable Courses",
  "CP Transferable Courses 71 credits",
  "Can make equivelnecy up to maximum if student has GPA 2.67 from PAAET",
  "C and above only to be equivelent for CCK majors.",
];

/** Equivalency entries available to a transfer student from a PAAET program. */
export function equivalencyForProgram(paaet_program: string): EquivalencyEntry[] {
  return EQUIVALENCY.filter((e) =>
    e.paaet_program.toLowerCase().includes(paaet_program.toLowerCase()),
  );
}

/** Per-course PAAET → CCK mappings for a given PAAET diploma. */
export function paaetEquivalencyForProgram(paaet_program: string): PaaetEquivalencyEntry[] {
  return PAAET_EQUIVALENCY.filter((e) =>
    e.paaet_program.toLowerCase().includes(paaet_program.toLowerCase()),
  );
}
